def validate(args, output):
    num, target = args[0], args[1]
    if not isinstance(output, list):
        return False
    # Build the set of all correct expressions via brute force
    def backtrack(idx, path, val, prev):
        if idx == len(num):
            if val == target:
                correct.add(path)
            return
        for end in range(idx + 1, len(num) + 1):
            s = num[idx:end]
            if len(s) > 1 and s[0] == '0':
                break  # no leading zeros
            n = int(s)
            if idx == 0:
                backtrack(end, s, n, n)
            else:
                backtrack(end, path + '+' + s, val + n, n)
                backtrack(end, path + '-' + s, val - n, -n)
                backtrack(end, path + '*' + s, val - prev + prev * n, prev * n)
    correct = set()
    backtrack(0, '', 0, 0)
    # Validate output
    seen = set()
    for expr in output:
        if not isinstance(expr, str):
            return False
        if expr in seen:
            return False  # no duplicates
        seen.add(expr)
        if expr not in correct:
            return False
    return seen == correct

