function validate(args, output) {
    const num = args[0], target = args[1];
    if (!Array.isArray(output)) return false;
    const correct = new Set();
    function backtrack(idx, path, val, prev) {
        if (idx === num.length) {
            if (val === target) correct.add(path);
            return;
        }
        for (let end = idx + 1; end <= num.length; end++) {
            const s = num.slice(idx, end);
            if (s.length > 1 && s[0] === '0') break;
            const n = parseInt(s);
            if (idx === 0) {
                backtrack(end, s, n, n);
            } else {
                backtrack(end, path + '+' + s, val + n, n);
                backtrack(end, path + '-' + s, val - n, -n);
                backtrack(end, path + '*' + s, val - prev + prev * n, prev * n);
            }
        }
    }
    backtrack(0, '', 0, 0);
    const seen = new Set();
    for (const expr of output) {
        if (typeof expr !== 'string') return false;
        if (seen.has(expr)) return false;
        seen.add(expr);
        if (!correct.has(expr)) return false;
    }
    if (seen.size !== correct.size) return false;
    for (const k of seen) if (!correct.has(k)) return false;
    return true;
}

